var AtomicReference = class {
	constructor(initialValue) {
		this.value = initialValue;
	}
	get() {
		return this.value;
	}
	set(newValue) {
		this.value = newValue;
	}
	compareAndSet(expect, update) {
		if (this.value === expect) {
			this.value = update;
			return true;
		}
		return false;
	}
};
